//! Attention Marketplace — Bule-based economic arbitrage for attention precision.
//!
//! Maps the thermodynamic refinement principles from `Gnosis.RefinementMarket` to
//! the distributed inference engine.
//!
//! Heads with high precision (on-shell, defect=0) can "sell" their cached attention
//! parameters to heads with high defect, in exchange for Bule budget.
//! This allows the mesh to trade precision locally instead of recomputing from scratch,
//! preserving total system energy while lowering collective defect.

use crate::karmic_attention_optimizer::{head_mesh_residual, HeadQkLedger};

/// Represents an active attention head holding a precision ledger and Bule balance.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct HeadState {
    pub key: String,
    pub bule_balance: u64,
    pub ledger: HeadQkLedger,
}

/// A trade proposal where a seller offers their precision state for a price.
#[derive(Debug, Clone)]
pub struct PrecisionTrade {
    pub seller_key: String,
    pub buyer_key: String,
    pub price_bule: u64,
    /// The defect improvement (reduction in residual) the seller offers
    pub offered_defect: u128,
}

/// Arbitrage check: is it cheaper for the buyer to buy the seller's precision
/// than to compute it themselves? (In our thermodynamic model, computing down
/// to defect D costs (current_defect - D) Bule).
pub fn is_trade_efficient(buyer: &HeadState, trade: &PrecisionTrade) -> bool {
    let current_defect = head_mesh_residual(&buyer.ledger);
    if trade.offered_defect >= current_defect {
        return false; // No improvement
    }

    // Cost to compute locally is linear to the defect reduction needed
    let local_cost = (current_defect - trade.offered_defect) as u64;

    trade.price_bule < local_cost && buyer.bule_balance >= trade.price_bule
}

/// Process a list of trades, updating the head states. Returns the number of successful trades.
pub fn settle_market(states: &mut [HeadState], trades: &[PrecisionTrade]) -> usize {
    let mut successful_trades = 0;

    for trade in trades {
        let buyer_idx = states.iter().position(|s| s.key == trade.buyer_key);
        let seller_idx = states.iter().position(|s| s.key == trade.seller_key);

        if let (Some(b_idx), Some(s_idx)) = (buyer_idx, seller_idx) {
            if b_idx == s_idx {
                continue;
            }

            let buyer_state = states[b_idx].clone();

            if is_trade_efficient(&buyer_state, trade) {
                // Execute trade
                states[b_idx].bule_balance -= trade.price_bule;
                states[s_idx].bule_balance += trade.price_bule;

                // Buyer adopts the seller's precision parameters
                states[b_idx].ledger.opportunity_k = states[s_idx].ledger.opportunity_k;
                states[b_idx].ledger.waste_q = states[s_idx].ledger.waste_q;

                successful_trades += 1;
            }
        }
    }

    successful_trades
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn trade_improves_precision_and_conserves_energy() {
        // Seller is on-shell (defect 0): lucas 4 = 7, fib 4 = 3
        let seller = HeadState {
            key: "0:0".to_string(),
            bule_balance: 100,
            ledger: HeadQkLedger {
                layer_index: 0,
                head_index: 0,
                waste_q: 3,
                opportunity_k: 7,
            },
        };

        // Buyer is off-shell (defect > 0)
        let buyer = HeadState {
            key: "0:1".to_string(),
            bule_balance: 10,
            ledger: HeadQkLedger {
                layer_index: 0,
                head_index: 1,
                waste_q: 1,
                opportunity_k: 1,
            },
        };

        let initial_buyer_defect = head_mesh_residual(&buyer.ledger);
        assert!(initial_buyer_defect > 0);

        let initial_total_bule = seller.bule_balance + buyer.bule_balance;

        let mut states = vec![seller.clone(), buyer.clone()];

        let trade = PrecisionTrade {
            seller_key: "0:0".to_string(),
            buyer_key: "0:1".to_string(),
            price_bule: 2,
            offered_defect: 0,
        };

        assert!(is_trade_efficient(&buyer, &trade));

        let success_count = settle_market(&mut states, &[trade]);
        assert_eq!(success_count, 1);

        let final_seller = &states[0];
        let final_buyer = &states[1];

        // Energy is conserved
        assert_eq!(
            final_seller.bule_balance + final_buyer.bule_balance,
            initial_total_bule
        );
        // Buyer paid, seller gained
        assert_eq!(final_buyer.bule_balance, 8);
        assert_eq!(final_seller.bule_balance, 102);

        // Buyer's defect is now 0 (on-shell)
        assert_eq!(head_mesh_residual(&final_buyer.ledger), 0);
    }
}
